var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으음, 이게 무슨 소리지?","JPN":"うん？　これは何の音？","ENG":"Mm... What's that noise?","TWN":"呃嗯，這是什麼聲音？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여긴, 아카데미? 아니야, 뭔가 다른데?","JPN":"ここはアカデミー？　いや、何かが違うような？","ENG":"Is this... the Academy? No, something's different.","TWN":"這裡是，學院？不對，不太一樣。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"오래 기다리셨습니다. 학생 여러분.","JPN":"生徒の皆様、お待たせいたしました。","ENG":"Dear students, thank you for your patience.","TWN":"同學們，大家久等了。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"조화와 화합의 학원제, 애쉬포드 학원제가 내일로 다가왔습니다. 모두 후회없는 축제 준비를 부탁드리겠습니다.","JPN":"いよいよ調和と和合の学園祭、アッシュフォード学園祭が明日へと迫りました。\\n皆さん、悔いのないように準備をお願いします。","ENG":"Tomorrow is the Harmony and Balance Festival at Ashford Academy. I hope everyone makes every effort to prepare for the festival.","TWN":"明天就是全校同歡的阿什弗德學園祭，請大家做足準備，不要留下遺憾。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"학원제라고? 분명 페스타는 중지…….","JPN":"学園祭！？　確か学園祭は中止するって……","ENG":"Festival? But I clearly remember her saying that it was canceled...","TWN":"學園祭？不是說暫停……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 내가 방금 무슨 말을 하려고 했더라?","JPN":"あれ？　私今何を言おうとしたんだっけ？","ENG":"Huh? What was I about to say just now?","TWN":"嗯？我剛要說什麼？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼, 나이엘 양. 학원제 예행연습을 해볼까요? 시작 구호는 올해 학년대표인 당신의 역할이었죠?","JPN":"では、ナイエルさん。明日の予行演習をしましょう。\\n学園祭開始の掛け声は今年の学年代表であるあなたの役でしたよね？","ENG":"Then, Naielle. Shall we do a rehearsal of the festival? As this year's student representative, you were in charge of shouting the slogan, correct?","TWN":"奈爾，那我們就來彩排吧？你是今年負責\\n喊開始口號的學生代表，你知道要做什麼吧？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"회장. 근데 이거 꼭 해야 돼?","JPN":"会長。これって必ずやらなきゃいけないの？","ENG":"Yen, do I really have to do this?","TWN":"會長，一定要這樣嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"물론이에요. 나이엘 양. 이건 애쉬포드의 전통이니까요.","JPN":"もちろんです、ナイエルさん。これはアッシュフォードの伝統ですから。","ENG":"Of course, Naielle. It's Ashford tradition.","TWN":"當然要。奈爾，這是阿什弗德的傳統。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으…… 그, 그럼……","JPN":"むう……、じ、じゃあ……","ENG":"Ugh... Th-then...","TWN":"喔……那，那好吧……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"냐, 냐……","JPN":"にゃ、にゃ……","ENG":"Me, meo–","TWN":"喵，喵……"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 못하겠어! 못하겠다구!! 전교생이 듣는데 부끄럽게 그걸 어떻게 해!?","JPN":"うう、やっぱりできない！　できないわよ！\\n全校生徒の前でこんな恥ずかしいことできるわけないでしょ！","ENG":"Bah! I can't do it! I just can't!! How can I say that in front of everybody without getting embarrassed?!","TWN":"唉唷，我不行啦！我做不到！！全校學生都會聽到欸，那麼害羞，我沒辦法啦！"},"stage":{"bg":"SKY","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"흐음, 역시 그런가요? 곤란하네요.","JPN":"ふむ、やはりそうですか。困りましたね。","ENG":"Hmm, is that so? That's a shame.","TWN":"嗯嗯，是嗎？真傷腦筋。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 양이 못하시겠다면, 시작 구호는 다른 학년 대표에게……","JPN":"ナイエルさんができないなら、他の学年の代表に……","ENG":"If you can't do it, Naielle, then we will need to give the honors to another repre–","TWN":"既然奈爾不行，那我只好找其他人來……"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건 안 돼!!","JPN":"そ、それはダメ！","ENG":"N-no!!","TWN":"不，不可以！！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으으, 내일은 진짜 제대로 할 수 있어! 믿어달라구, 회장!","JPN":"うう、明日はちゃんとできるから！　信じてよ、会長！","ENG":"Errgh, I'll do it properly tomorrow! I promise!","TWN":"那個，我明天一定會好好表現的！你相信我，會長！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐야, 지금 건? 전야제 준비 방송인가?","JPN":"なんだ、今の？　前夜祭の準備放送か？","ENG":"Huh? What was that? Was that the rehearsal broadcast for tomorrow's festival?","TWN":"剛那是怎樣？是在彩排嗎？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐, 평소대로의 학생회 같은 분위기잖아? 내일 학원제가 기대되는 걸?","JPN":"ふふっ。でも、生徒会らしいじゃない。明日の学園祭が楽しみね。","ENG":"Well, it's just any other day for the Student Council. Anyway, I'm hyped about tomorrow's festival!","TWN":"不是學生會的日常發揮嗎？真期待明天的學園祭。"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 대체 뭐가 어떻게 돌아가는 거야?","JPN":"ちょっと待って、いったい何がどうなっているの？","ENG":"Wait a minute. What's going on around here?","TWN":"等等，現在到底是什麼情況？"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_QM","text":{"KOREA":"미나야!","JPN":"ミナ！","ENG":"Mina!","TWN":"米娜！"},"stage":{"bg":"GEASS_ASHFORD","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};